"use client";

import React, { useState, useEffect } from "react";
import MobileHeader from "@/components/mobile/MobileHeader";
import MobileFinScore from "@/components/mobile/MobileFinScore";
import MobileLeakBuster from "@/components/mobile/MobileLeakBuster";
import MobileBottomBar from "@/components/mobile/MobileBottomBar";
import { useFinScore, useTransactions, addTransaction } from "@/lib/hooks";

// ID del usuario de demo (el que se creó con el seed). 
// En producción esto vendría de supabase.auth.getUser()
const DEMO_USER_ID = "00000000-0000-0000-0000-000000000001";

export default function MobileApp() {
  const { score: finScore, loading: scoreLoading, refresh: refreshScore } = useFinScore(DEMO_USER_ID);
  const { gastoHormigaTotal, gastosHormigaCount, transactions, loading: txLoading, refresh: refreshTx } = useTransactions(DEMO_USER_ID);

  // Fallback mientras carga
  const displayScore = scoreLoading ? 650 : finScore;

  const handleAddTransaction = async (amount: number, category: string) => {
    const isGasto = amount < 0;

    await addTransaction({
      user_id: DEMO_USER_ID,
      tipo: isGasto ? "gasto" : "ingreso",
      monto: Math.abs(amount),
      categoria: category,
      descripcion: category,
      metodo_entrada: "audio",
      confianza_ia: 0.95,
      confirmada_por_usuario: false,
      es_gasto_hormiga: isGasto && Math.abs(amount) < 50000,
      fecha_transaccion: new Date().toISOString().split("T")[0],
    });

    // Refrescar datos
    await refreshScore();
    await refreshTx();
  };

  return (
    <div className="flex flex-col w-full h-full px-4 overflow-y-auto no-scrollbar relative">
      <MobileHeader />
      <MobileFinScore score={displayScore} loading={scoreLoading} />
      <MobileLeakBuster 
        gastoHormigaTotal={gastoHormigaTotal}
        gastosHormigaCount={gastosHormigaCount}
        transactions={transactions}
        loading={txLoading}
      />
      <MobileBottomBar onTransactionAdd={handleAddTransaction} />
    </div>
  );
}
