import { useEffect, useState, useCallback } from 'react'
import { supabase, Profile, Transaction, FinScoreHistory } from '@/lib/supabase'

// ─── Hook: Perfil del usuario ─────────────────────────────────────────────────
export function useProfile(userId: string) {
  const [profile, setProfile] = useState<Profile | null>(null)
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState<string | null>(null)

  useEffect(() => {
    if (!userId) return
    const fetch = async () => {
      setLoading(true)
      const { data, error } = await supabase
        .from('profiles')
        .select('*')
        .eq('id', userId)
        .single()
      if (error) setError(error.message)
      else setProfile(data)
      setLoading(false)
    }
    fetch()
  }, [userId])

  return { profile, loading, error }
}

// ─── Hook: FinScore actual + historia ────────────────────────────────────────
export function useFinScore(userId: string) {
  const [score, setScore] = useState<number>(0)
  const [history, setHistory] = useState<FinScoreHistory[]>([])
  const [loading, setLoading] = useState(true)

  const refresh = useCallback(async () => {
    if (!userId) return
    setLoading(true)

    // Score actual desde el perfil
    const { data: profileData } = await supabase
      .from('profiles')
      .select('finscore_actual')
      .eq('id', userId)
      .single()

    if (profileData) setScore(profileData.finscore_actual)

    // Historia de los últimos 7 días
    const { data: histData } = await supabase
      .from('finscore_history')
      .select('*')
      .eq('user_id', userId)
      .order('fecha', { ascending: false })
      .limit(7)

    if (histData) setHistory(histData)
    setLoading(false)
  }, [userId])

  useEffect(() => { refresh() }, [refresh])

  return { score, history, loading, refresh }
}

// ─── Hook: Transacciones recientes (gastos hormiga) ───────────────────────────
export function useTransactions(userId: string) {
  const [transactions, setTransactions] = useState<Transaction[]>([])
  const [gastoHormigaTotal, setGastoHormigaTotal] = useState(0)
  const [gastosHormigaCount, setGastosHormigaCount] = useState(0)
  const [loading, setLoading] = useState(true)

  const refresh = useCallback(async () => {
    if (!userId) return
    setLoading(true)

    const { data } = await supabase
      .from('transactions')
      .select('*')
      .eq('user_id', userId)
      .order('fecha_transaccion', { ascending: false })
      .limit(20)

    if (data) {
      setTransactions(data)
      // Calcular gastos hormiga del mes
      const hormigaTxns = data.filter((t) => t.es_gasto_hormiga === true)
      const total = hormigaTxns.reduce((acc, t) => acc + Number(t.monto), 0)
      setGastoHormigaTotal(total)
      setGastosHormigaCount(hormigaTxns.length)
    }
    setLoading(false)
  }, [userId])

  useEffect(() => { refresh() }, [refresh])

  return { transactions, gastoHormigaTotal, gastosHormigaCount, loading, refresh }
}

// ─── Acción: Agregar transacción ──────────────────────────────────────────────
export async function addTransaction(tx: Omit<Transaction, 'id' | 'created_at'>) {
  const { data, error } = await supabase
    .from('transactions')
    .insert([tx])
    .select()
    .single()

  if (error) {
    console.error('Error al guardar transacción:', error.message)
    return { ok: false, error: error.message }
  }

  // Actualizar el FinScore: si es gasto, restar 15 puntos
  if (tx.tipo === 'gasto') {
    await supabase.rpc('update_finscore', { 
      p_user_id: tx.user_id, 
      p_delta: tx.es_gasto_hormiga ? -20 : -10 
    }).maybeSingle()

    // Fallback: actualizar directamente si la función no existe
    const { data: prof } = await supabase
      .from('profiles')
      .select('finscore_actual')
      .eq('id', tx.user_id)
      .single()
    
    if (prof) {
      const newScore = Math.max(0, prof.finscore_actual - (tx.es_gasto_hormiga ? 20 : 10))
      await supabase
        .from('profiles')
        .update({ finscore_actual: newScore, updated_at: new Date().toISOString() })
        .eq('id', tx.user_id)
    }
  }

  return { ok: true, data }
}
